import { consolidationService } from './ConsolidationService';
import { Transaction } from '../types';
import { Logger } from './monitoringService';
import { DateResolver } from '../core/processors/DateResolver';
import { NameResolver } from '../core/processors/NameResolver';

// Cache global para evitar race conditions em uploads simultâneos
const hashesInFlight = new Set<string>();

export const LaunchService = {
    /**
     * 🛡️ FUNIL CENTRAL DE NORMALIZAÇÃO
     * Garante paridade absoluta entre fontes (PDF, CSV, Gmail, DB).
     */
    normalizeTriplet: (t: any) => {
        // 1. Data Normalizada (YYYY-MM-DD)
        let rawDate = String(t.date || t.transaction_date || '').trim();
        let isoDate = rawDate;
        if (rawDate && !/^\d{4}-\d{2}-\d{2}$/.test(rawDate)) {
            const resolved = DateResolver.resolveToISO(rawDate, new Date().getFullYear());
            if (resolved) isoDate = resolved;
        }
        const finalDate = isoDate || rawDate || '0000-00-00';

        // 2. Nome Normalizado (Caixa alta, sem acentos, sem espaços extras)
        // Usa a descrição que já passou pelo processamento de limpeza do StrategyEngine/Parser
        const cleanName = NameResolver.normalize(t.description || t.rawDescription || 'SEM_DESCRICAO');

        // 3. Valor Normalizado (String com 2 casas decimais)
        const finalValue = Number(t.amount || 0).toFixed(2);

        return { finalDate, cleanName, finalValue };
    },

    /**
     * Gera a CHAVE ÚNICA DE BLINDAGEM: DATA|NOME|VALOR
     */
    computeBaseHash: (t: any, userId: string) => {
        const { finalDate, cleanName, finalValue } = LaunchService.normalizeTriplet(t);
        const rawKey = `U${userId}|D${finalDate}|N${cleanName}|V${finalValue}`;

        let hash = 5381;
        for (let i = 0; i < rawKey.length; i++) {
            hash = ((hash << 5) + hash) + rawKey.charCodeAt(i);
        }
        return `viva_${Math.abs(hash).toString(36)}`;
    },

    async launchToBank(
        userId: string, 
        bankId: string, 
        transactions: Transaction[],
        source: 'file' | 'gmail' = 'file'
    ): Promise<{ added: number, skipped: number, total: number }> {
        if (!userId || !transactions || transactions.length === 0) {
            return { added: 0, skipped: 0, total: transactions ? transactions.length : 0 };
        }

        const totalReceived = transactions.length;
        const isUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);
        const currentBankId = isUuid ? bankId : null;

        try {
            // 1. Busca hashes existentes para evitar duplicidade com o passado
            const existingData = await consolidationService.getExistingTransactionsForDedup(userId);
            const existingHashes = new Set(existingData.map(t => t.row_hash).filter(Boolean));

            const toPersist = transactions
                .map(item => {
                    const finalRowHash = this.computeBaseHash(item, userId);

                    // 🛡️ DEDUPE TRIPLO (O FUNIL): Banco + Em trânsito + Lote Atual
                    if (existingHashes.has(finalRowHash) || hashesInFlight.has(finalRowHash)) {
                        return null; 
                    }

                    hashesInFlight.add(finalRowHash);

                    const { finalDate } = this.normalizeTriplet(item);

                    return {
                        transaction_date: finalDate,
                        amount: item.amount,
                        description: item.description, 
                        type: (item.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: currentBankId ? (item.paymentMethod || 'OUTROS') : bankId, 
                        source: source,
                        user_id: userId,
                        bank_id: currentBankId,
                        row_hash: finalRowHash,
                        status: 'pending' as const
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null);

            const novosCount = toPersist.length;

            if (novosCount > 0) {
                await consolidationService.addTransactions(toPersist as any);
            }

            // Limpeza curta do cache in-flight
            setTimeout(() => {
                toPersist.forEach(t => { if(t.row_hash) hashesInFlight.delete(t.row_hash); });
            }, 5000);

            return { added: novosCount, skipped: totalReceived - novosCount, total: totalReceived };

        } catch (e: any) {
            hashesInFlight.clear();
            Logger.error(`[Launch:DEDUPE_FAIL]`, e);
            throw e;
        }
    },

    async clearBankLaunch(userId: string, bankId: string): Promise<boolean> {
        try {
            return await consolidationService.deletePendingTransactions(userId, bankId);
        } catch (error) {
            throw error;
        }
    }
};

import { useEffect, useCallback, useRef, useState } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';
import { LaunchService } from '../services/LaunchService';
import { useUI } from '../contexts/UIContext';

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds
}: any) => {
    const { showToast } = useUI();
    const isHydrating = useRef(false);
    const lastUserId = useRef<string | null>(null);
    const [isCleaning, setIsCleaning] = useState(false);
    const [syncError, setSyncError] = useState<string | null>(null);

    /**
     * 🛡️ BUILD KEY (ESPELHO DO LAUNCHSERVICE)
     * Garante que a UI e o Banco usem o mesmo DNA para dedupe.
     */
    const buildKey = (tx: any, userId: string) => {
        return LaunchService.computeBaseHash(tx, userId);
    };

    const hydrate = useCallback(async (forceClearUI: boolean = false) => {
        if (!user || isCleaning || isHydrating.current) return;

        isHydrating.current = true;
        setSyncError(null);

        try {
            if (forceClearUI) {
                setBankStatementFile(() => []);
                setSelectedBankIds(() => []);
            }

            // Busca as pendências reais do banco
            const dbTransactions = await consolidationService.getPendingTransactions(user.id);

            if (!dbTransactions || dbTransactions.length === 0) {
                if (forceClearUI) {
                    setBankStatementFile(() => []);
                    setSelectedBankIds(() => []);
                }
                isHydrating.current = false;
                return;
            }

            const groupedByBank: Record<string, Transaction[]> = {};
            dbTransactions.forEach((t: any) => {
                let bankId = t.bank_id;
                if (!bankId && t.pix_key && t.pix_key.includes('-')) {
                    bankId = t.pix_key;
                }
                const finalBankId = bankId || 'virtual';

                const tx: Transaction = {
                    id: t.id,
                    date: t.transaction_date,
                    description: t.description,
                    rawDescription: t.description,
                    amount: t.amount,
                    originalAmount: String(t.amount.toFixed(2)),
                    contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                    paymentMethod: t.pix_key || 'OUTROS',
                    cleanedDescription: t.description,
                    bank_id: t.bank_id
                };

                if (!groupedByBank[finalBankId]) groupedByBank[finalBankId] = [];
                groupedByBank[finalBankId].push(tx);
            });

            const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                bankId,
                fileName: bankId.includes('gmail')
                    ? 'Importação Gmail'
                    : (bankId === 'virtual' ? 'Lista Virtual' : `Lista Viva Sincronizada`),
                processedTransactions: txs,
                isRestored: true
            }));

            // ✅ MERGE COM BLINDAGEM DE DUPLICATAS
            setBankStatementFile((prev: any[]) => {
                const finalMap = new Map<string, any>();

                // 1. Preserva o que já está na UI
                if (prev) prev.forEach(f => finalMap.set(f.bankId, f));

                // 2. Funde com o Banco aplicando o Triplet Check
                restoredFiles.forEach(dbFile => {
                    if (finalMap.has(dbFile.bankId)) {
                        const uiFile = finalMap.get(dbFile.bankId);
                        const txMap = new Map<string, Transaction>();

                        // Mapeia usando a chave normalizada
                        uiFile.processedTransactions.forEach((tx: Transaction) => {
                            const key = buildKey(tx, user.id);
                            txMap.set(key, tx);
                        });

                        dbFile.processedTransactions.forEach((tx: Transaction) => {
                            const key = buildKey(tx, user.id);
                            // O banco sempre vence em caso de colisão por ter ID real
                            txMap.set(key, tx);
                        });

                        finalMap.set(dbFile.bankId, {
                            ...uiFile,
                            processedTransactions: Array.from(txMap.values())
                        });
                    } else {
                        finalMap.set(dbFile.bankId, dbFile);
                    }
                });

                return Array.from(finalMap.values());
            });

            setSelectedBankIds((prev: string[]) => {
                const availableIds = restoredFiles.map(f => f.bankId);
                return Array.from(new Set([...prev, ...availableIds]));
            });

        } catch (err: any) {
            console.error("[Lista Viva] Erro na hidratação:", err);
        } finally {
            isHydrating.current = false;
        }
    }, [user, isCleaning, setBankStatementFile, setSelectedBankIds]);

    useEffect(() => {
        if (user?.id && user.id !== lastUserId.current) {
            lastUserId.current = user.id;
            hydrate(true);
        }
    }, [user, hydrate]);

    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user) return { added: 0, skipped: 0, total: transactions.length };

        try {
            const stats = await LaunchService.launchToBank(user.id, bankId, transactions);
            await hydrate(false);
            return stats;
        } catch (e: any) {
            showToast("Erro no Lançamento: " + (e.message || "Erro de rede."), "error");
            throw e; 
        }
    }, [user, showToast, hydrate]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        setIsCleaning(true);
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            if (bankId && bankId !== 'all') {
                setBankStatementFile((prev: any[]) => prev.filter(f => f.bankId !== bankId));
                setSelectedBankIds((prev: string[]) => prev.filter(id => id !== bankId));
            } else {
                setBankStatementFile([]);
                setSelectedBankIds([]);
            }
        } finally {
            setIsCleaning(false);
            await hydrate(false);
        }
    }, [user, setBankStatementFile, setSelectedBankIds, hydrate]);

    return { persistTransactions, clearRemoteList, hydrate, syncError };
};

import { consolidationService } from './ConsolidationService';
import { Transaction } from '../types';
import { Logger } from './monitoringService';
import { DateResolver } from '../core/processors/DateResolver';
import { NameResolver } from '../core/processors/NameResolver';

// Cache global para evitar race conditions em uploads simultâneos ou cliques duplos
const hashesInFlight = new Set<string>();

export const LaunchService = {
    /**
     * 🛡️ FUNIL CENTRAL DE NORMALIZAÇÃO
     * Define o padrão ouro para o triplet (Data, Nome, Valor).
     */
    normalizeTriplet: (t: any) => {
        // 1. Data (YYYY-MM-DD)
        let rawDate = String(t.date || t.transaction_date || '').trim();
        let isoDate = rawDate;
        if (rawDate && !/^\d{4}-\d{2}-\d{2}$/.test(rawDate)) {
            const resolved = DateResolver.resolveToISO(rawDate, new Date().getFullYear());
            if (resolved) isoDate = resolved;
        }
        const finalDate = isoDate || rawDate || '0000-00-00';

        // 2. Nome (Fiel ao processamento do sistema, sem ruído)
        // O NameResolver.normalize garante remoção de acentos e caixa alta
        const cleanName = NameResolver.normalize(t.description || t.rawDescription || 'SEM_DESCRICAO');

        // 3. Valor (String fixa com 2 casas decimais)
        const finalValue = Number(t.amount || 0).toFixed(2);

        return { finalDate, cleanName, finalValue };
    },

    /**
     * Gera a CHAVE ÚNICA DE BLINDAGEM: DATA|NOME|VALOR
     */
    computeBaseHash: (t: any, userId: string) => {
        const { finalDate, cleanName, finalValue } = LaunchService.normalizeTriplet(t);
        const rawKey = `U${userId}|D${finalDate}|N${cleanName}|V${finalValue}`;

        let hash = 5381;
        for (let i = 0; i < rawKey.length; i++) {
            hash = ((hash << 5) + hash) + rawKey.charCodeAt(i);
        }
        return `viva_${Math.abs(hash).toString(36)}`;
    },

    /**
     * 🚀 O ÚNICO PONTO DE ENTRADA PARA PERSISTÊNCIA NA LISTA VIVA
     * Verifica duplicatas contra o histórico total do usuário no banco.
     */
    async launchToBank(
        userId: string, 
        bankId: string, 
        transactions: Transaction[],
        source: 'file' | 'gmail' = 'file'
    ): Promise<{ added: number, skipped: number, total: number }> {
        if (!userId || !transactions || transactions.length === 0) {
            return { added: 0, skipped: 0, total: transactions?.length || 0 };
        }

        const totalReceived = transactions.length;
        const isUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);
        const currentBankId = isUuid ? bankId : null;

        try {
            // 1. Busca hashes existentes (Dedupe contra histórico total: Pendentes + Reconciliados)
            const existingData = await consolidationService.getExistingTransactionsForDedup(userId);
            const existingHashes = new Set(existingData.map(t => t.row_hash).filter(Boolean));

            const toPersist = transactions
                .map(item => {
                    const finalRowHash = this.computeBaseHash(item, userId);

                    // 🛡️ FILTRO DE BLINDAGEM (O FUNIL)
                    if (existingHashes.has(finalRowHash) || hashesInFlight.has(finalRowHash)) {
                        return null; 
                    }

                    hashesInFlight.add(finalRowHash);

                    const { finalDate } = this.normalizeTriplet(item);

                    return {
                        transaction_date: finalDate,
                        amount: item.amount,
                        description: item.description, 
                        type: (item.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: currentBankId ? (item.paymentMethod || 'OUTROS') : bankId, 
                        source: source,
                        user_id: userId,
                        bank_id: currentBankId,
                        row_hash: finalRowHash,
                        status: 'pending' as const
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null);

            const novosCount = toPersist.length;

            if (novosCount > 0) {
                await consolidationService.addTransactions(toPersist as any);
            }

            // Limpeza curta do cache in-flight para permitir re-upload se deletado
            setTimeout(() => {
                toPersist.forEach(t => { if(t.row_hash) hashesInFlight.delete(t.row_hash); });
            }, 5000);

            return { added: novosCount, skipped: totalReceived - novosCount, total: totalReceived };

        } catch (e: any) {
            Logger.error(`[LaunchService:DEDUPE_FAIL]`, e);
            throw e;
        }
    },

    async clearBankLaunch(userId: string, bankId: string): Promise<boolean> {
        try {
            return await consolidationService.deletePendingTransactions(userId, bankId);
        } catch (error) {
            throw error;
        }
    }
};

import { useEffect, useCallback, useRef, useState } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';
import { LaunchService } from '../services/LaunchService';
import { useUI } from '../contexts/UIContext';

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds
}: any) => {
    const { showToast } = useUI();
    const isHydrating = useRef(false);
    const lastUserId = useRef<string | null>(null);
    const [isCleaning, setIsCleaning] = useState(false);
    const [syncError, setSyncError] = useState<string | null>(null);

    /**
     * 🛡️ HYDRATE (O FUNIL DE SAÍDA PARA A UI)
     * Garante que a UI só exiba o que está validado no banco de dados.
     */
    const hydrate = useCallback(async (forceClearUI: boolean = false) => {
        if (!user || isCleaning || isHydrating.current) return;

        isHydrating.current = true;
        setSyncError(null);

        try {
            // Busca as transações 'pending' reais do banco (A Lista Viva de verdade)
            const dbTransactions = await consolidationService.getPendingTransactions(user.id);

            if (!dbTransactions || dbTransactions.length === 0) {
                setBankStatementFile([]);
                if (forceClearUI) setSelectedBankIds([]);
                isHydrating.current = false;
                return;
            }

            // Agrupa por banco para manter a estrutura da UI
            const groupedByBank: Record<string, Transaction[]> = {};
            dbTransactions.forEach((t: any) => {
                let bankId = t.bank_id;
                // Fallback para IDs virtuais legados
                if (!bankId && t.pix_key && t.pix_key.includes('-')) {
                    bankId = t.pix_key;
                }
                const finalBankId = bankId || 'virtual';

                const tx: Transaction = {
                    id: t.id,
                    date: t.transaction_date,
                    description: t.description,
                    rawDescription: t.description,
                    amount: t.amount,
                    originalAmount: String(t.amount.toFixed(2)),
                    contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                    paymentMethod: t.pix_key || 'OUTROS',
                    cleanedDescription: t.description,
                    bank_id: t.bank_id
                };

                if (!groupedByBank[finalBankId]) groupedByBank[finalBankId] = [];
                groupedByBank[finalBankId].push(tx);
            });

            const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                bankId,
                fileName: bankId.includes('gmail')
                    ? 'Importação Gmail'
                    : (bankId === 'virtual' ? 'Lista Virtual' : `Lista Viva Sincronizada`),
                processedTransactions: txs,
                isRestored: true
            }));

            // ✅ ATUALIZAÇÃO ÚNICA DA UI
            setBankStatementFile(restoredFiles);

            if (forceClearUI) {
                setSelectedBankIds(restoredFiles.map(f => f.bankId));
            } else {
                setSelectedBankIds((prev: string[]) => {
                    const availableIds = restoredFiles.map(f => f.bankId);
                    // Preserva a seleção se o banco ainda existir
                    return prev.filter(id => availableIds.includes(id));
                });
            }

        } catch (err: any) {
            console.error("[Lista Viva] Erro na sincronização da UI:", err);
            setSyncError("Falha ao sincronizar dados.");
        } finally {
            isHydrating.current = false;
        }
    }, [user, isCleaning, setBankStatementFile, setSelectedBankIds]);

    useEffect(() => {
        if (user?.id && user.id !== lastUserId.current) {
            lastUserId.current = user.id;
            hydrate(true);
        }
    }, [user, hydrate]);

    /**
     * 📥 PERSIST (O FUNIL DE ENTRADA)
     * Toda inserção (Upload/Sync) deve passar por aqui.
     */
    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user) return { added: 0, skipped: 0, total: transactions.length };

        try {
            // Delega para o funil central de dedupe e persistência
            const stats = await LaunchService.launchToBank(user.id, bankId, transactions);

            // Após a inserção blindada, reidrata a UI a partir do Banco
            await hydrate(false);

            return stats;
        } catch (e: any) {
            showToast("Erro no Lançamento: " + (e.message || "Erro de rede."), "error");
            throw e; 
        }
    }, [user, showToast, hydrate]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        setIsCleaning(true);
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
        } finally {
            setIsCleaning(false);
            await hydrate(false);
        }
    }, [user, hydrate]);

    return { persistTransactions, clearRemoteList, hydrate, syncError };
};

import React, { useContext, useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { useUI } from '../../contexts/UIContext';
import { 
    XMarkIcon, 
    BoltIcon, 
    BanknotesIcon, 
    UserIcon, 
    TrashIcon, 
    CheckCircleIcon, 
    ArrowUturnLeftIcon, 
    ArrowPathIcon, 
    CloudArrowUpIcon, 
    PlusCircleIcon, 
    UploadIcon, 
    EnvelopeIcon, 
    EllipsisVerticalIcon 
} from '../Icons';
import { FileUploader, FileUploaderHandle } from '../FileUploader';
import { GmailModal } from '../../features/gmail/GmailModal';
import { processFileContent } from '../../services/processingService';
import { LaunchService } from '../../services/LaunchService';
import { useAuth } from '../../contexts/AuthContext';

const BankRow: React.FC<{ 
    bank: any, 
    isUploaded: boolean, 
    handleStatementUpload: any, 
    setIsGmailModalOpen: any, 
    removeBankStatementFile: any,
    triggerUpdate: () => void 
}> = ({ bank, isUploaded, handleStatementUpload, setIsGmailModalOpen, removeBankStatementFile, triggerUpdate }) => {

    const { fileModels, effectiveIgnoreKeywords, setModelRequiredData, persistTransactions } = useContext(AppContext);
    const { user } = useAuth();
    const { showToast } = useUI();

    const [menuOpen, setMenuOpen] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [menuPosition, setMenuPosition] = useState({ top: 0, left: 0 });

    const uploaderRef = useRef<FileUploaderHandle>(null);
    const buttonRef = useRef<HTMLButtonElement>(null);
    const uploadModeRef = useRef<'replace' | 'append'>('replace');

    const toggleMenu = () => {
        if (menuOpen) {
            setMenuOpen(false);
        } else if (buttonRef.current) {
            const rect = buttonRef.current.getBoundingClientRect();
            setMenuPosition({ top: rect.bottom + window.scrollY + 5, left: rect.right - 224 + window.scrollX });
            setMenuOpen(true);
        }
    };

    const handleAppend = async (content: string, fileName: string, rawFile: File, base64?: string) => {
        if (!user) return;
        setIsUploading(true);
        try {
            const result = await processFileContent(content, fileName, fileModels, effectiveIgnoreKeywords, base64);

            if (result.status === 'MODEL_REQUIRED') {
                if (setModelRequiredData) {
                    setModelRequiredData({ ...result, fileName, bankId: bank.id });
                }
                setIsUploading(false);
                return;
            }

            const newTransactions = result.transactions;

            if (!newTransactions || newTransactions.length === 0) {
                showToast("Nenhuma transação válida encontrada.", "error");
                setIsUploading(false);
                return;
            }

            // 🛡️ FUNIL CENTRAL: O persistTransactions cuida do dedupe e do hydrate automático da UI
            const launchResult = await persistTransactions(bank.id, newTransactions);

            if (launchResult.added > 0) {
                showToast(`${launchResult.added} transações adicionadas!`, "success");
            } else {
                showToast("Nenhuma transação nova detectada (duplicatas ignoradas).", "success");
            }

            triggerUpdate();

        } catch (e: any) {
            showToast("Erro ao adicionar: " + e.message, "error");
        } finally {
            setIsUploading(false);
        }
    };

    const handleFileUploadWrapper = async (content: string, fileName: string, rawFile: File, base64?: string) => {
        setIsUploading(true);
        if (uploadModeRef.current === 'replace') {
            await handleStatementUpload(content, fileName, bank.id, rawFile, base64);
        } else {
            await handleAppend(content, fileName, rawFile, base64);
        }
        setIsUploading(false);
        setMenuOpen(false);
    };

    const triggerUpload = (mode: 'replace' | 'append') => {
        uploadModeRef.current = mode;
        uploaderRef.current?.open();
        setMenuOpen(false);
    };

    return (
        <div className={`p-3 rounded-2xl border transition-all duration-200 flex items-center justify-between gap-3 relative ${isUploaded ? 'bg-emerald-50/50 border-emerald-200 dark:bg-emerald-900/10 dark:border-emerald-800' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'}`}>
            <div className="hidden"><FileUploader ref={uploaderRef} id={`update-bank-${bank.id}`} title="Up" onFileUpload={handleFileUploadWrapper} isUploaded={false} uploadedFileName={null} onParsingStatusChange={setIsUploading} /></div>
