import React, { useState, useRef, useEffect, useContext, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useAuth } from '../contexts/AuthContext';
import { useUI } from '../contexts/UIContext';
import { processFileContent } from '../services/processingService';
import { LaunchService } from '../services/LaunchService';

interface UseSmartBankCardProps {
    bank: any;
}

export const useSmartBankCard = ({ bank }: UseSmartBankCardProps) => {
    const { 
        activeBankFiles,
        handleStatementUpload, 
        fileModels,
        effectiveIgnoreKeywords,
        persistTransactions,
        hydrate,
        setModelRequiredData 
    } = useContext(AppContext);

    const { user } = useAuth();
    const { showToast } = useUI();

    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [menuPos, setMenuPos] = useState<{x: number, y: number} | null>(null);
    const [isDragging, setIsDragging] = useState(false);

    const dragStartRef = useRef<{x: number, y: number}>({ x: 0, y: 0 });
    const uploaderRef = useRef<any>(null);
    const menuRef = useRef<HTMLDivElement>(null);
    const uploadModeRef = useRef<'replace' | 'append'>('replace');

    const bankFiles = activeBankFiles.filter((f: any) => f.bankId === bank.id);
    const totalTransactions = bankFiles.reduce((acc: number, f: any) => acc + (f.processedTransactions?.length || 0), 0);

    const handleMouseDown = (e: React.MouseEvent) => {
        if (menuRef.current) {
            setIsDragging(true);
            const rect = menuRef.current.getBoundingClientRect();
            dragStartRef.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
        }
    };

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (isDragging) {
                setMenuPos({ x: e.clientX - dragStartRef.current.x, y: e.clientY - dragStartRef.current.y });
            }
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging]);

    const handleAppend = async (content: string, fileName: string, rawFile: File, base64?: string) => {
        if (!user) return;
        setIsUploading(true);
        try {
            const result = await processFileContent(content, fileName, fileModels, effectiveIgnoreKeywords, base64);

            if (result.status === 'MODEL_REQUIRED') {
                if (setModelRequiredData) {
                    setModelRequiredData({ ...result, fileName, bankId: bank.id });
                }
                setIsUploading(false);
                return;
            }

            const newTransactions = result.transactions;

            if (!newTransactions || newTransactions.length === 0) {
                showToast("Nenhuma transação encontrada no arquivo.", "error");
                setIsUploading(false);
                return;
            }

            // 🛡️ FUNIL CENTRAL: Delega para o persistTransactions do hook de sincronização
            const launchResult = await persistTransactions(bank.id, newTransactions);

            if (launchResult.added > 0) {
                showToast(`${launchResult.added} transações adicionadas!`, "success");
            } else {
                showToast("Registros já existentes ignorados.", "success");
            }
        } catch (e: any) {
            showToast("Erro ao adicionar: " + e.message, "error");
        } finally {
            setIsUploading(false);
        }
    };

    const handleFileUploadWrapper = async (content: string, fileName: string, rawFile: File, base64?: string) => {
        setIsUploading(true);
        try {
            if (uploadModeRef.current === 'replace') {
                await handleStatementUpload(content, fileName, bank.id, rawFile, base64);
            } else {
                await handleAppend(content, fileName, rawFile, base64);
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsUploading(false);
            setIsMenuOpen(false);
        }
    };

    const triggerUpload = (mode: 'replace' | 'append') => {
        uploadModeRef.current = mode;
        uploaderRef.current?.open();
        setIsMenuOpen(false);
    };

    const removeSpecificFile = async (fileToRemove: any) => {
        if (!user) return;
        setIsUploading(true);
        setIsMenuOpen(false);

        try {
            // No modo blindado, qualquer remoção física exige re-sincronia do banco
            // 1. Identifica os arquivos que permanecerão
            const remainingFiles = bankFiles.filter((f: any) => f !== fileToRemove);

            // 2. Limpa todos os pendentes deste banco
            await LaunchService.clearBankLaunch(user.id, bank.id);

            // 3. Re-insere apenas os que sobraram (o launchToBank fará o dedupe novamente)
            if (remainingFiles.length > 0) {
                const allTxs = remainingFiles.flatMap((f: any) => f.processedTransactions || []);
                if (allTxs.length > 0) {
                    await LaunchService.launchToBank(user.id, bank.id, allTxs);
                }
            }

            // 4. Reidrata a UI a partir da única fonte de verdade
            await hydrate(false);

            showToast("Arquivo removido.", "success");
        } catch (e: any) {
            showToast("Erro ao remover arquivo.", "error");
        } finally {
            setIsUploading(false);
        }
    };

    return {
        isMenuOpen, setIsMenuOpen,
        isUploading, setIsUploading,
        menuPos, setMenuPos,
        isDragging,
        uploaderRef,
        menuRef,
        bankFiles,
        totalTransactions,
        handleMouseDown,
        handleFileUploadWrapper,
        triggerUpload,
        removeSpecificFile
    };
};

import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';
import { DateResolver } from '../core/processors/DateResolver';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

export const consolidationService = {
    /**
     * Adiciona transações em lote com CHUNKING para evitar estouro de buffer e timeout.
     */
    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        try {
            const sanitizedPayload = transactions
                .map(t => {
                    const amount = Number(t.amount);
                    let finalDate = t.transaction_date;

                    if (finalDate && !/^\d{4}-\d{2}-\d{2}$/.test(finalDate)) {
                        const resolved = DateResolver.resolveToISO(finalDate, new Date().getFullYear());
                        if (resolved) finalDate = resolved;
                    }

                    if (!finalDate || !/^\d{4}-\d{2}-\d{2}$/.test(finalDate)) {
                        finalDate = new Date().toISOString().split('T')[0];
                    }

                    return {
                        transaction_date: finalDate,
                        amount: isNaN(amount) ? 0 : amount,
                        description: t.description,
                        type: t.type || (amount >= 0 ? 'income' : 'expense'),
                        pix_key: t.pix_key || null,
                        source: t.source || 'file',
                        user_id: t.user_id,
                        bank_id: t.bank_id || null, 
                        status: t.status || 'pending',
                        row_hash: t.row_hash
                    };
                })
                .filter((item): item is NonNullable<typeof item> => item !== null && !!item.user_id);

            if (sanitizedPayload.length === 0) return [];

            const CHUNK_SIZE = 100; // Reduzido para maior estabilidade em lotes grandes
            const results = [];

            for (let i = 0; i < sanitizedPayload.length; i += CHUNK_SIZE) {
                const chunk = sanitizedPayload.slice(i, i + CHUNK_SIZE);

                const { data, error } = await supabase
                    .from('consolidated_transactions')
                    .insert(chunk)
                    .select('*'); 

                if (error) {
                    console.error("[Consolidation:INSERT_ERROR]", error);
                    throw new Error(error.message);
                }
                if (data) results.push(...data);
            }

            return results;
        } catch (e: any) {
            console.error("[Consolidation:CRITICAL_FAIL]", e);
            throw e;
        }
    },

    updateTransactionStatus: async (id: string, status: 'pending' | 'identified' | 'resolved') => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .update({ status })
                .eq('id', id);

            if (error) throw error;
            return true;
        } catch (error) {
            console.error("[Consolidation] Erro ao atualizar status:", error);
            return false;
        }
    },

    /**
     * Recupera hashes existentes para deduplicação com PAGINAÇÃO AUTOMÁTICA.
     * Varre todo o histórico do banco sem limites fixos.
     */
    getExistingTransactionsForDedup: async (userId: string) => {
        if (!userId) throw new Error("UserID é obrigatório.");

        let allHashes: { row_hash: string | null }[] = [];
        let from = 0;
        const step = 1000;
        let hasMore = true;

        try {
            while (hasMore) {
                const { data, error } = await supabase
                    .from('consolidated_transactions')
                    .select('row_hash')
                    .eq('user_id', userId)
                    .range(from, from + step - 1);

                if (error) throw error;

                if (data && data.length > 0) {
                    allHashes = [...allHashes, ...data];
                    from += step;
                    if (data.length < step) hasMore = false;
                } else {
                    hasMore = false;
                }
            }
            return allHashes;
        } catch (e: any) {
            console.error("[Consolidation:DEDUP_FETCH_FAIL]", e);
            throw e;
        }
    },

    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            if (!userId) return false;

            let query = supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending');

            if (bankId && bankId !== 'all') {
                const isVirtual = bankId === 'gmail-sync' || bankId === 'virtual' || bankId === 'gmail-virtual-bank';
                const isProbablyUuid = /^[0-9a-fA-F-]{36}$/.test(bankId);
                if (isVirtual || !isProbablyUuid) query = query.is('bank_id', null);
                else query = query.eq('bank_id', bankId);
            }
            const { error } = await query;
            if (error) throw error;
            return true;
        } catch (error) {
            throw error;
        }
    },

    /**
     * Recupera transações pendentes (Lista Viva) com PAGINAÇÃO AUTOMÁTICA.
     * Remove o teto fixo e garante a recuperação integral dos dados do usuário.
     */
    getPendingTransactions: async (userId: string) => {
        if (!userId) return [];

        let allTransactions: any[] = [];
        let from = 0;
        const step = 1000;
        let hasMore = true;

        try {
            while (hasMore) {
                const { data, error } = await supabase
                    .from('consolidated_transactions')
                    .select('id, transaction_date, amount, description, type, bank_id, row_hash, pix_key')
                    .eq('user_id', userId)
                    .eq('status', 'pending')
                    .order('transaction_date', { ascending: false })
                    .range(from, from + step - 1);

                if (error) throw error;

                if (data && data.length > 0) {
                    allTransactions = [...allTransactions, ...data];
                    from += step;
                    // Se o bloco veio incompleto, atingimos o fim da tabela
                    if (data.length < step) hasMore = false;
                } else {
                    hasMore = false;
                }
            }
            return allTransactions;
        } catch (e: any) {
            console.error("[Consolidation:FETCH_FAIL]", e);
            throw e; 
        }
    },

    deleteTransactionById: async (id: string) => {
        try {
            const { error } = await supabase
                .from('consolidated_transactions')
                .delete()
                .eq('id', id);

            if (error) throw error;
            return true;
        } catch (error) {
            throw error;
        }
    }
};
